import sys
def quicksort(arr):
    if len(arr) <= 1:
        return arr
    pivot = arr[len(arr) // 2]
    left = [x for x in arr if x[2] > pivot[2]]
    middle = [x for x in arr if x[2] == pivot[2]]
    right = [x for x in arr if x[2] < pivot[2]]
    return quicksort(left) + middle + quicksort(right)
input = sys.stdin.read().split()
idx = 0
N, W = int(input[idx]), float(input[idx+1])
idx += 2
bottles = list(map(int, input[idx:idx+N])); idx += N
prices = list(map(int, input[idx:idx+N])); idx += N
general = quicksort([(bottles[i], prices[i], prices[i] / bottles[i], i) for i in range(N)])
result = [0.0] * N
total = 0.0
remaining = W
for i in range(N): 
    if remaining <= 0:
        break
    volume, price, sp, idx = general[i]
    if remaining >= volume:
        result[idx] = volume
        total += price
        remaining -= volume
    else:
        result[idx] = remaining
        total += price * remaining / volume
        remaining = 0
        break

print(f"{total:.1f}")
print(' '.join(f"{x:.1f}" for x in result))

