# Идея решения была взята из лекции неделя 9 слайд 4
import sys
input = sys.stdin.read().split()
N,X = int(input[0]), int(input[1]) 
cubes = list(map(int, input[2:]))
count = [0] * 26 
for w in cubes:
    exp = 0
    temp = w
    while temp > 1:
        temp //= 2
        exp += 1
    count[exp] += 1
result = []
for exp in range(25, -1, -1):
    result.extend([2**exp] * count[exp])
container = []
floor_sums = []
for cube in result:
    placed = False
    for i in range(len(container)):
            if floor_sums[i]+cube <= X:
                container[i].append(cube)
                floor_sums[i] += cube
                placed = True
                break
    if not placed:
        if len(container) >= N:
            print(-1)
            exit()
        container.append([cube])
        floor_sums.append(cube)
print(len(container))
for floor in container:
    print(*floor)
