def quicksort_asc(arr):
    if len(arr) <= 1:
        return arr
    pivot = arr[len(arr) // 2]
    left = [x for x in arr if x < pivot]
    middle = [x for x in arr if x == pivot]
    right = [x for x in arr if x > pivot]
    return quicksort_asc(left) + middle + quicksort_asc(right)
def quicksort_lexa(arr):
    if len(arr) <= 1:
        return arr
    pivot = arr[len(arr) // 2]
    left = [x for x in arr if x[1] < pivot[1] or (x[1] == pivot[1] and x[0] < pivot[0])]
    middle = [x for x in arr if x[0] == pivot[0] and x[1] == pivot[1]]
    right = [x for x in arr if x[1] > pivot[1] or (x[1] == pivot[1] and x[0] > pivot[0])]
    return quicksort_lexa(left) + middle + quicksort_lexa(right)
