def try_kill_all():
    lev_temp = lev_sorted[:] 
    damage = 0
    for def_power in def_cards:
        found_index = -1
        for j in range(len(lev_temp)):
            if lev_temp[j] > def_power:
                found_index = j
                break
        if found_index == -1:
            return 0
        lev_temp.pop(found_index)
    for atk_power in atk_cards:
        found_index = -1
        for j in range(len(lev_temp)):
            if lev_temp[j] >= atk_power:
                found_index = j
